import{_ as a,o as t,c as o,a2 as r}from"./chunks/framework.BZO4qERu.js";const p=JSON.parse('{"title":"FAQ","description":"Frequently asked questions about WebRouter","frontmatter":{"title":"FAQ","description":"Frequently asked questions about WebRouter"},"headers":[],"relativePath":"guide/faq.md","filePath":"guide/faq.md"}'),i={name:"guide/faq.md"};function s(n,e,l,h,d,u){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h1><h2 id="general" tabindex="-1">General <a class="header-anchor" href="#general" aria-label="Permalink to &quot;General&quot;">​</a></h2><h3 id="what-is-webrouter" tabindex="-1">What is WebRouter? <a class="header-anchor" href="#what-is-webrouter" aria-label="Permalink to &quot;What is WebRouter?&quot;">​</a></h3><p>WebRouter is an open-source AI API gateway that provides a unified management interface for multiple LLM providers. It handles provider health monitoring, smart routing, cost tracking, team management, and privacy desensitization.</p><h3 id="who-is-webrouter-for" tabindex="-1">Who is WebRouter for? <a class="header-anchor" href="#who-is-webrouter-for" aria-label="Permalink to &quot;Who is WebRouter for?&quot;">​</a></h3><ul><li><strong>Developers</strong> who want a single API key for multiple AI providers</li><li><strong>Engineering teams</strong> that need cost visibility and quota management</li><li><strong>Companies</strong> that need to manage and monitor AI API usage across their organization</li></ul><h3 id="do-i-need-to-use-wr-proxy" tabindex="-1">Do I need to use wr-proxy? <a class="header-anchor" href="#do-i-need-to-use-wr-proxy" aria-label="Permalink to &quot;Do I need to use wr-proxy?&quot;">​</a></h3><p>wr-proxy is the high-performance Go proxy that handles request forwarding, retry, and desensitization. You can run the Flask admin panel without it for configuration and monitoring, but wr-proxy is needed for actual API proxying.</p><h2 id="licensing" tabindex="-1">Licensing <a class="header-anchor" href="#licensing" aria-label="Permalink to &quot;Licensing&quot;">​</a></h2><h3 id="what-license-does-webrouter-use" tabindex="-1">What license does WebRouter use? <a class="header-anchor" href="#what-license-does-webrouter-use" aria-label="Permalink to &quot;What license does WebRouter use?&quot;">​</a></h3><p>The Community Edition (CE) uses the <strong>Business Source License 1.1 (BSL 1.1)</strong>. On <strong>June 1, 2029</strong>, it automatically converts to Apache License 2.0.</p><h3 id="can-i-use-webrouter-for-free" tabindex="-1">Can I use WebRouter for free? <a class="header-anchor" href="#can-i-use-webrouter-for-free" aria-label="Permalink to &quot;Can I use WebRouter for free?&quot;">​</a></h3><p>Yes. The CE is free for:</p><ul><li>Personal use</li><li>Internal production use within an organization</li><li>Learning and research</li><li>Modifying and contributing code</li></ul><h3 id="what-is-not-allowed-under-bsl-1-1" tabindex="-1">What is not allowed under BSL 1.1? <a class="header-anchor" href="#what-is-not-allowed-under-bsl-1-1" aria-label="Permalink to &quot;What is not allowed under BSL 1.1?&quot;">​</a></h3><ul><li>Selling WebRouter or derivative works as a commercial product</li><li>Offering paid hosted/managed services of WebRouter</li><li>OEM embedding in a closed-source product</li></ul><h3 id="what-is-the-change-date" tabindex="-1">What is the Change Date? <a class="header-anchor" href="#what-is-the-change-date" aria-label="Permalink to &quot;What is the Change Date?&quot;">​</a></h3><p>June 1, 2029. After this date, the Community Edition automatically becomes Apache 2.0, removing all commercial restrictions.</p><h3 id="what-about-the-enterprise-edition" tabindex="-1">What about the Enterprise Edition? <a class="header-anchor" href="#what-about-the-enterprise-edition" aria-label="Permalink to &quot;What about the Enterprise Edition?&quot;">​</a></h3><p>The Enterprise Edition (EE) uses a proprietary EULA and includes:</p><ul><li>SSO/SAML/OIDC integration</li><li>Advanced audit logging</li><li>Cluster deployment</li><li>Enhanced alerting channels (DingTalk, Feishu, Slack, PagerDuty)</li><li>Commercial support with SLA</li></ul><h2 id="technical" tabindex="-1">Technical <a class="header-anchor" href="#technical" aria-label="Permalink to &quot;Technical&quot;">​</a></h2><h3 id="what-databases-are-supported" tabindex="-1">What databases are supported? <a class="header-anchor" href="#what-databases-are-supported" aria-label="Permalink to &quot;What databases are supported?&quot;">​</a></h3><p>SQLite is the default (zero configuration). MySQL and PostgreSQL are also supported by setting <code>DATABASE_URI</code>.</p><h3 id="does-webrouter-support-streaming" tabindex="-1">Does WebRouter support streaming? <a class="header-anchor" href="#does-webrouter-support-streaming" aria-label="Permalink to &quot;Does WebRouter support streaming?&quot;">​</a></h3><p>Yes. wr-proxy supports streaming responses (SSE).</p><h3 id="can-i-run-webrouter-without-docker" tabindex="-1">Can I run WebRouter without Docker? <a class="header-anchor" href="#can-i-run-webrouter-without-docker" aria-label="Permalink to &quot;Can I run WebRouter without Docker?&quot;">​</a></h3><p>Yes. The install script (<code>deploy/install.sh</code>) handles everything on bare metal.</p><h3 id="how-are-api-keys-managed" tabindex="-1">How are API keys managed? <a class="header-anchor" href="#how-are-api-keys-managed" aria-label="Permalink to &quot;How are API keys managed?&quot;">​</a></h3><p>WebRouter generates unique API keys per token. Each token has configurable model access, quotas, rate limits, and desensitization settings.</p><h3 id="what-provider-types-are-supported" tabindex="-1">What provider types are supported? <a class="header-anchor" href="#what-provider-types-are-supported" aria-label="Permalink to &quot;What provider types are supported?&quot;">​</a></h3><p><code>direct</code>, <code>aggregate</code>, <code>newapi</code>, <code>oneapi</code>, <code>litellm</code>, and <code>custom</code> — any OpenAI-compatible provider.</p><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><h3 id="health-checks-show-dead-for-my-provider" tabindex="-1">Health checks show &quot;dead&quot; for my provider <a class="header-anchor" href="#health-checks-show-dead-for-my-provider" aria-label="Permalink to &quot;Health checks show &quot;dead&quot; for my provider&quot;">​</a></h3><ol><li>Verify the Base URL is correct</li><li>Check that the API key is valid</li><li>Ensure the provider is accessible from your server (no firewall blocks)</li><li>Check the provider status page for outages</li></ol><h3 id="tokens-not-working" tabindex="-1">Tokens not working <a class="header-anchor" href="#tokens-not-working" aria-label="Permalink to &quot;Tokens not working&quot;">​</a></h3><ol><li>Verify the token is enabled</li><li>Check quota hasn&#39;t been exhausted</li><li>Ensure the requested model is in the token&#39;s whitelist</li><li>Check rate limit hasn&#39;t been exceeded</li></ol><h3 id="how-do-i-reset-the-admin-password" tabindex="-1">How do I reset the admin password? <a class="header-anchor" href="#how-do-i-reset-the-admin-password" aria-label="Permalink to &quot;How do I reset the admin password?&quot;">​</a></h3><p>Set the environment variable and restart:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">WEBROUTER_ADMIN_PASSWORD</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">newpassword</span></span></code></pre></div>',40)])])}const b=a(i,[["render",s]]);export{p as __pageData,b as default};
